async function sendAjaxRequest(r,e,t,s){return fetch(r,{method:e,body:t,headers:{"X-CSRFToken":t.get("csrf_token")}}).then((async r=>{let e;try{e=await r.json()}catch(t){e={result:"error",msg:"Resposta não é um JSON válido",raw:await r.text()}}return r.ok?e:{result:"error",msg:`Erro HTTP: ${r.status} ${r.statusText}`,...e}})).then((r=>(s&&s(r),r))).catch((r=>{const e={result:"error",msg:"Erro inesperado ao processar a requisição",error:r.message||r};return s&&s(e),e}))}async function receiveAjaxRequest(r){try{const e=await fetch(r,{method:"GET"});if(!e.ok)return{result:"error",msg:`Erro HTTP: ${e.status} ${e.statusText}`};return await e.json()}catch(r){return{result:"error",msg:"Erro inesperado ao processar a resposta",error:r.message||r}}}